class SalesProcessor:
    def __init__(self, records):
        self.records = records

    def total_revenue(self):
        return sum(r['price'] * r['quantity'] for r in self.records)

    def filter_by_category(self, category):
        return [r for r in self.records if r['category'] == category]

    def top_n_by_revenue(self, n):
        sorted_records = sorted(
            self.records,
            key=lambda r: r['price'] * r['quantity'],
            reverse=True
        )
        return sorted_records[:n]

    def average_price(self):
        if not self.records:
            return 0.0
        return sum(r['price'] for r in self.records) / len(self.records)

    def category_summary(self):
        summary = {}
        for r in self.records:
            cat = r['category']
            if cat not in summary:
                summary[cat] = {'count': 0, 'revenue': 0}
            summary[cat]['count'] += 1
            summary[cat]['revenue'] += r['price'] * r['quantity']
        return summary

# Test data
TEST_DATA = [
    {'name': 'Widget A', 'category': 'widgets', 'price': 10.00, 'quantity': 5},
    {'name': 'Widget B', 'category': 'widgets', 'price': 20.00, 'quantity': 3},
    {'name': 'Gadget X', 'category': 'gadgets', 'price': 50.00, 'quantity': 2},
    {'name': 'Tool Y',   'category': 'tools',   'price': 15.00, 'quantity': 4},
]

# TODO: Write 8+ test functions that use assert statements
# Each test function should print "PASS: test_name" when it passes
# Use try/except AssertionError to catch failures and print "FAIL: test_name"

def run_test(test_func):
    try:
        test_func()
        print(f"PASS: {test_func.__name__}")
    except AssertionError as e:
        print(f"FAIL: {test_func.__name__}: {e}")

def test_total_revenue():
    proc = SalesProcessor(TEST_DATA)
    # 10*5 + 20*3 + 50*2 + 15*4 = 50 + 60 + 100 + 60 = 270
    assert proc.total_revenue() == 270.0, f"Expected 270, got {proc.total_revenue()}"

def test_empty_total():
    proc = SalesProcessor([])
    assert proc.total_revenue() == 0

def test_filter_category():
    proc = SalesProcessor(TEST_DATA)
    widgets = proc.filter_by_category('widgets')
    assert len(widgets) == 2
    assert all(w['category'] == 'widgets' for w in widgets)

def test_filter_empty_category():
    proc = SalesProcessor(TEST_DATA)
    result = proc.filter_by_category('nonexistent')
    assert result == []

def test_top_n():
    proc = SalesProcessor(TEST_DATA)
    top2 = proc.top_n_by_revenue(2)
    assert len(top2) == 2
    # Gadget X revenue=100 is highest, Widget B revenue=60 is second
    assert top2[0]['name'] == 'Gadget X'
    assert top2[1]['name'] == 'Widget B'

def test_average_price():
    proc = SalesProcessor(TEST_DATA)
    # (10 + 20 + 50 + 15) / 4 = 23.75
    assert proc.average_price() == 23.75

def test_average_price_empty():
    proc = SalesProcessor([])
    assert proc.average_price() == 0.0

def test_category_summary():
    proc = SalesProcessor(TEST_DATA)
    summary = proc.category_summary()
    assert 'widgets' in summary
    assert summary['widgets']['count'] == 2
    assert summary['widgets']['revenue'] == 110.0  # 50 + 60

# Run all tests
for test in [test_total_revenue, test_empty_total, test_filter_category,
             test_filter_empty_category, test_top_n, test_average_price,
             test_average_price_empty, test_category_summary]:
    run_test(test)

class DataFetcher:
    def __init__(self, api_client=None):
        """Accept optional api_client for dependency injection."""
        self.api_client = api_client or self._default_client
        self._call_log = []

    def _default_client(self, url):
        """Would make real HTTP call — NOT used in tests."""
        raise RuntimeError("Real HTTP call not allowed in tests!")

    def fetch_users(self):
        """Fetch users from API."""
        self._call_log.append('fetch_users')
        data = self.api_client("/api/users")
        return data.get("users", [])

    def fetch_user(self, user_id):
        """Fetch a single user."""
        self._call_log.append(f'fetch_user/{user_id}')
        data = self.api_client(f"/api/users/{user_id}")
        return data.get("user")

    def fetch_stats(self):
        """Fetch and summarize user stats."""
        users = self.fetch_users()
        return {
            "count": len(users),
            "names": [u["name"] for u in users],
        }

# TODO: Create a mock API client function
def make_mock_client():
    """
    Returns a mock API function that returns fake data.
    Mock responses:
      GET /api/users -> {"users": [{"id": 1, "name": "Alice"}, {"id": 2, "name": "Bob"}]}
      GET /api/users/1 -> {"user": {"id": 1, "name": "Alice", "email": "alice@test.com"}}
      GET /api/users/99 -> {"user": None}
    """
    def mock_client(url):
        # TODO: Return appropriate mock responses based on url
        pass
    return mock_client

# Tests
def run_test(func):
    try:
        func()
        print(f"PASS: {func.__name__}")
    except AssertionError as e:
        print(f"FAIL: {func.__name__}: {e}")

def test_fetch_users():
    mock = make_mock_client()
    fetcher = DataFetcher(api_client=mock)
    users = fetcher.fetch_users()
    assert len(users) == 2
    assert users[0]["name"] == "Alice"

def test_fetch_user():
    mock = make_mock_client()
    fetcher = DataFetcher(api_client=mock)
    user = fetcher.fetch_user(1)
    assert user is not None
    assert user["email"] == "alice@test.com"

def test_fetch_missing_user():
    mock = make_mock_client()
    fetcher = DataFetcher(api_client=mock)
    user = fetcher.fetch_user(99)
    assert user is None

def test_fetch_stats():
    mock = make_mock_client()
    fetcher = DataFetcher(api_client=mock)
    stats = fetcher.fetch_stats()
    assert stats["count"] == 2
    assert "Alice" in stats["names"]
    assert "Bob" in stats["names"]

def test_call_log():
    mock = make_mock_client()
    fetcher = DataFetcher(api_client=mock)
    fetcher.fetch_users()
    fetcher.fetch_user(1)
    assert fetcher._call_log == ['fetch_users', 'fetch_user/1']

for test in [test_fetch_users, test_fetch_user, test_fetch_missing_user,
             test_fetch_stats, test_call_log]:
    run_test(test)

